9	export function buildModelOutputProperty(field: DMMF.Field, dmmf: DMMFHelper) {
10	  let fieldTypeName = hasOwnProperty(GraphQLScalarToJSTypeTable, field.type)
11	    ? GraphQLScalarToJSTypeTable[field.type]
12	    : field.type
13	  if (Array.isArray(fieldTypeName)) {
14	    fieldTypeName = fieldTypeName[0]
15	  }
16	
17	  if (needsNamespace(field)) {
18	    fieldTypeName = `Prisma.${fieldTypeName}`
19	  }
20	  let fieldType: ts.TypeBuilder
21	  if (field.kind === 'object') {
22	    const payloadType = ts.namedType(getPayloadName(field.type))
23	    if (!dmmf.isComposite(field.type)) {
24	      payloadType.addGenericArgument(ts.namedType('ExtArgs'))
25	    }
26	    fieldType = payloadType
27	  } else if (field.kind === 'enum') {
28	    fieldType = ts.namedType(`$Enums.${fieldTypeName}`)
29	  } else {
30	    fieldType = ts.namedType(fieldTypeName)
31	  }
32	
33	  if (field.isList) {
34	    fieldType = ts.array(fieldType)
35	  } else if (!field.isRequired) {
36	    fieldType = ts.unionType(fieldType).addVariant(ts.nullType)
37	  }
38	  const property = ts.property(field.name, fieldType)
39	  if (field.documentation) {
40	    property.setDocComment(ts.docComment(field.documentation))
41	  }
42	  return property
43	}
