/**
 * Maps Prisma scalar types to TypeScript types for the generated REST API client.
 */
const scalarTypeMap: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  Decimal: 'string',
  BigInt: 'bigint',
  DateTime: 'Date',
  Json: 'unknown',
  Bytes: 'Buffer',
}

/**
 * Resolves a Prisma field type to its TypeScript representation.
 * For scalar types, uses the known mapping. For enums, uses the enum name directly.
 * For object (relation) types, uses the related model name.
 */
export function mapFieldType(type: string, kind: string): string {
  if (kind === 'scalar') {
    return scalarTypeMap[type] ?? 'unknown'
  }

  // Enum and object (relation) types use their own name as the TS type
  return type
}

