import type * as DMMF from '@prisma/dmmf'

import { mapFieldType } from './type-mapping'

/**
 * Generates the complete TypeScript REST API client source from a DMMF document.
 */
export function generateRestApiClient(dmmf: DMMF.Document): string {
  const lines: string[] = []

  lines.push(generateHeader())

  for (const enumDef of dmmf.datamodel.enums) {
    lines.push(generateEnum(enumDef))
  }

  for (const model of dmmf.datamodel.models) {
    lines.push(generateModelInterface(model, dmmf.datamodel.models))
    lines.push(generateCreateInput(model))
    lines.push(generateUpdateInput(model))
    lines.push(generateWhereUniqueInput(model))
    lines.push(generateWhereInput(model))
  }

  lines.push(generateRestApiClientClass(dmmf.datamodel.models))

  return lines.join('\n')
}

function generateHeader(): string {
  return `// Generated by @prisma/rest-api-generator — do not edit manually

/** Configuration for the REST API client. */
export interface RestApiClientConfig {
  /** Base URL of the REST API (e.g. "https://api.example.com"). */
  baseUrl: string
  /** Optional headers included with every request. */
  headers?: Record<string, string>
}

type RequestOptions = {
  method: string
  path: string
  body?: unknown
  query?: Record<string, string>
}
`
}

function generateEnum(enumDef: DMMF.DatamodelEnum): string {
  const values = enumDef.values.map((v) => `  ${v.name} = '${v.name}',`).join('\n')
  return `export enum ${enumDef.name} {\n${values}\n}\n`
}

function generateModelInterface(model: DMMF.Model, allModels: readonly DMMF.Model[]): string {
  const modelNames = new Set(allModels.map((m) => m.name))
  const fields = model.fields
    .map((field) => {
      // Skip relation fields in the base interface — they are returned as nested objects
      // only when explicitly included; keeping them optional here.
      const tsType = mapFieldType(field.type, field.kind)
      const isRelation = field.kind === 'object' && modelNames.has(field.type)
      let fullType = tsType
      if (field.isList) {
        fullType = `${tsType}[]`
      }
      const optional = !field.isRequired || isRelation ? '?' : ''
      return `  ${field.name}${optional}: ${fullType}`
    })
    .join('\n')

  const doc = model.documentation ? `/** ${model.documentation} */\n` : ''
  return `${doc}export interface ${model.name} {\n${fields}\n}\n`
}

function generateCreateInput(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => {
      if (f.kind === 'object') return false
      if (f.isReadOnly) return false
      if (f.isGenerated) return false
      if (f.isUpdatedAt) return false
      if (f.hasDefaultValue) return false
      if (f.isId && f.hasDefaultValue) return false
      return true
    })
    .map((field) => {
      const tsType = mapFieldType(field.type, field.kind)
      const fullType = field.isList ? `${tsType}[]` : tsType
      const optional = !field.isRequired ? '?' : ''
      return `  ${field.name}${optional}: ${fullType}`
    })
    .join('\n')

  // Also include fields with defaults as optional
  const optionalDefaults = model.fields
    .filter((f) => {
      if (f.kind === 'object') return false
      if (f.isReadOnly) return false
      if (f.isUpdatedAt) return false
      return f.hasDefaultValue
    })
    .map((field) => {
      const tsType = mapFieldType(field.type, field.kind)
      const fullType = field.isList ? `${tsType}[]` : tsType
      return `  ${field.name}?: ${fullType}`
    })
    .join('\n')

  const allFields = [fields, optionalDefaults].filter(Boolean).join('\n')
  return `export interface ${model.name}CreateInput {\n${allFields}\n}\n`
}

function generateUpdateInput(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'object' && !f.isReadOnly)
    .map((field) => {
      const tsType = mapFieldType(field.type, field.kind)
      const fullType = field.isList ? `${tsType}[]` : tsType
      return `  ${field.name}?: ${fullType}`
    })
    .join('\n')

  return `export interface ${model.name}UpdateInput {\n${fields}\n}\n`
}

function generateWhereUniqueInput(model: DMMF.Model): string {
  const uniqueFields = model.fields.filter((f) => f.isId || f.isUnique)
  if (uniqueFields.length === 0) {
    // Fallback: use all scalar fields as optional
    const fields = model.fields
      .filter((f) => f.kind === 'scalar')
      .map((f) => `  ${f.name}?: ${mapFieldType(f.type, f.kind)}`)
      .join('\n')
    return `export interface ${model.name}WhereUniqueInput {\n${fields}\n}\n`
  }

  const fields = uniqueFields
    .map((f) => {
      const tsType = mapFieldType(f.type, f.kind)
      return `  ${f.name}?: ${tsType}`
    })
    .join('\n')

  return `export interface ${model.name}WhereUniqueInput {\n${fields}\n}\n`
}

function generateWhereInput(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => f.kind === 'scalar' || f.kind === 'enum')
    .map((f) => {
      const tsType = mapFieldType(f.type, f.kind)
      return `  ${f.name}?: ${tsType}`
    })
    .join('\n')

  return `export interface ${model.name}WhereInput {\n${fields}\n}\n`
}

function generateRestApiClientClass(models: readonly DMMF.Model[]): string {
  const lines: string[] = []

  lines.push(`/** Typed REST API client generated from the Prisma schema. */`)
  lines.push(`export class RestApiClient {`)
  lines.push(`  #baseUrl: string`)
  lines.push(`  #headers: Record<string, string>`)
  lines.push(``)
  lines.push(`  constructor(config: RestApiClientConfig) {`)
  lines.push(`    this.#baseUrl = config.baseUrl.replace(/\\/+$/, '')`)
  lines.push(`    this.#headers = {`)
  lines.push(`      'Content-Type': 'application/json',`)
  lines.push(`      ...config.headers,`)
  lines.push(`    }`)
  lines.push(`  }`)
  lines.push(``)
  lines.push(`  async #request<T>(options: RequestOptions): Promise<T> {`)
  lines.push(`    const url = new URL(\`\${this.#baseUrl}\${options.path}\`)`)
  lines.push(`    if (options.query) {`)
  lines.push(`      for (const [key, value] of Object.entries(options.query)) {`)
  lines.push(`        url.searchParams.set(key, value)`)
  lines.push(`      }`)
  lines.push(`    }`)
  lines.push(`    const response = await fetch(url.toString(), {`)
  lines.push(`      method: options.method,`)
  lines.push(`      headers: this.#headers,`)
  lines.push(`      body: options.body ? JSON.stringify(options.body) : undefined,`)
  lines.push(`    })`)
  lines.push(`    if (!response.ok) {`)
  lines.push(`      throw new Error(\`REST API error: \${response.status} \${response.statusText}\`)`)
  lines.push(`    }`)
  lines.push(`    return response.json() as Promise<T>`)
  lines.push(`  }`)

  for (const model of models) {
    const name = model.name
    const resource = toResourcePath(name)

    lines.push(``)
    lines.push(`  // --- ${name} ---`)
    lines.push(``)
    lines.push(`  /** Find many ${name} records, optionally filtered. */`)
    lines.push(`  async ${camelCase(name)}FindMany(where?: ${name}WhereInput): Promise<${name}[]> {`)
    lines.push(`    const query: Record<string, string> = {}`)
    lines.push(`    if (where) {`)
    lines.push(`      for (const [key, value] of Object.entries(where)) {`)
    lines.push(`        if (value !== undefined) query[key] = String(value)`)
    lines.push(`      }`)
    lines.push(`    }`)
    lines.push(`    return this.#request<${name}[]>({ method: 'GET', path: '/${resource}', query })`)
    lines.push(`  }`)
    lines.push(``)
    lines.push(`  /** Find a unique ${name} record. */`)
    lines.push(`  async ${camelCase(name)}FindUnique(where: ${name}WhereUniqueInput): Promise<${name} | null> {`)
    lines.push(`    const query: Record<string, string> = {}`)
    lines.push(`    for (const [key, value] of Object.entries(where)) {`)
    lines.push(`      if (value !== undefined) query[key] = String(value)`)
    lines.push(`    }`)
    lines.push(
      `    return this.#request<${name} | null>({ method: 'GET', path: '/${resource}/unique', query })`,
    )
    lines.push(`  }`)
    lines.push(``)
    lines.push(`  /** Create a new ${name} record. */`)
    lines.push(`  async ${camelCase(name)}Create(data: ${name}CreateInput): Promise<${name}> {`)
    lines.push(
      `    return this.#request<${name}>({ method: 'POST', path: '/${resource}', body: data })`,
    )
    lines.push(`  }`)
    lines.push(``)
    lines.push(`  /** Update an existing ${name} record. */`)
    lines.push(
      `  async ${camelCase(name)}Update(where: ${name}WhereUniqueInput, data: ${name}UpdateInput): Promise<${name}> {`,
    )
    lines.push(
      `    return this.#request<${name}>({ method: 'PATCH', path: '/${resource}', body: { where, data } })`,
    )
    lines.push(`  }`)
    lines.push(``)
    lines.push(`  /** Delete a ${name} record. */`)
    lines.push(
      `  async ${camelCase(name)}Delete(where: ${name}WhereUniqueInput): Promise<${name}> {`,
    )
    lines.push(
      `    return this.#request<${name}>({ method: 'DELETE', path: '/${resource}', body: { where } })`,
    )
    lines.push(`  }`)
  }

  lines.push(`}`)
  lines.push(``)

  return lines.join('\n')
}

function camelCase(name: string): string {
  return name.charAt(0).toLowerCase() + name.slice(1)
}

function toResourcePath(name: string): string {
  // Convert PascalCase to kebab-case for REST resource paths
  return name
    .replace(/([a-z0-9])([A-Z])/g, '$1-$2')
    .replace(/([A-Z])([A-Z][a-z])/g, '$1-$2')
    .toLowerCase()
}

