import fs from 'node:fs'
import path from 'node:path'

import type { GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'

import type { Generator } from '@prisma/generator'

import { generateRestApiClient } from './generate-code'

/**
 * Prisma generator that produces a typed REST API client with TypeScript
 * interfaces and CRUD methods for each model in the schema.
 */
export class RestApiGenerator implements Generator {
  readonly name = 'prisma-rest-api-generator'

  async getManifest(_config: GeneratorConfig): Promise<GeneratorManifest> {
    return {
      prettyName: 'Prisma REST API Client',
      defaultOutput: './generated/rest-api-client',
    }
  }

  async generate(options: GeneratorOptions): Promise<void> {
    const output = options.generator.output
    if (!output?.value) {
      throw new Error('No output directory specified for prisma-rest-api-generator')
    }

    const outputDir = output.value
    fs.mkdirSync(outputDir, { recursive: true })

    const code = generateRestApiClient(options.dmmf)
    const outputPath = path.join(outputDir, 'index.ts')
    fs.writeFileSync(outputPath, code, 'utf-8')
  }
}

