import type * as DMMF from '@prisma/dmmf'
import { describe, expect, test } from 'vitest'

import { generateRestApiClient } from '../generate-code'
import { mapFieldType } from '../type-mapping'

function createField(overrides: Partial<DMMF.Field>): DMMF.Field {
  return {
    kind: 'scalar',
    name: 'field',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    type: 'String',
    hasDefaultValue: false,
    ...overrides,
  }
}

function createModel(name: string, fields: DMMF.Field[]): DMMF.Model {
  return {
    name,
    dbName: null,
    schema: null,
    fields,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
  }
}

function createDmmf(models: DMMF.Model[], enums: DMMF.DatamodelEnum[] = []): DMMF.Document {
  return {
    datamodel: {
      models,
      enums,
      types: [],
      indexes: [],
    },
    schema: {
      inputObjectTypes: {},
      outputObjectTypes: { model: [], prisma: [] },
      enumTypes: { prisma: [] },
      fieldRefTypes: {},
    },
    mappings: {
      modelOperations: [],
      otherOperations: { read: [], write: [] },
    },
  }
}

describe('mapFieldType', () => {
  test('maps scalar types correctly', () => {
    expect(mapFieldType('String', 'scalar')).toBe('string')
    expect(mapFieldType('Int', 'scalar')).toBe('number')
    expect(mapFieldType('Float', 'scalar')).toBe('number')
    expect(mapFieldType('Boolean', 'scalar')).toBe('boolean')
    expect(mapFieldType('DateTime', 'scalar')).toBe('Date')
    expect(mapFieldType('BigInt', 'scalar')).toBe('bigint')
    expect(mapFieldType('Decimal', 'scalar')).toBe('string')
    expect(mapFieldType('Json', 'scalar')).toBe('unknown')
    expect(mapFieldType('Bytes', 'scalar')).toBe('Buffer')
  })

  test('returns unknown for unrecognized scalar types', () => {
    expect(mapFieldType('CustomScalar', 'scalar')).toBe('unknown')
  })

  test('returns the type name for enums', () => {
    expect(mapFieldType('Role', 'enum')).toBe('Role')
  })

  test('returns the type name for object relations', () => {
    expect(mapFieldType('Post', 'object')).toBe('Post')
  })
})

describe('generateRestApiClient', () => {
  test('generates header with RestApiClientConfig', () => {
    const result = generateRestApiClient(createDmmf([]))
    expect(result).toContain('export interface RestApiClientConfig')
    expect(result).toContain('baseUrl: string')
    expect(result).toContain('headers?: Record<string, string>')
  })

  test('generates interface for a simple model', () => {
    const model = createModel('User', [
      createField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
      createField({ name: 'email', type: 'String', isUnique: true }),
      createField({ name: 'name', type: 'String', isRequired: false }),
    ])

    const result = generateRestApiClient(createDmmf([model]))

    expect(result).toContain('export interface User {')
    expect(result).toContain('  id: number')
    expect(result).toContain('  email: string')
    expect(result).toContain('  name?: string')
  })

  test('generates CreateInput with required and optional fields', () => {
    const model = createModel('User', [
      createField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
      createField({ name: 'email', type: 'String' }),
      createField({ name: 'name', type: 'String', isRequired: false }),
    ])

    const result = generateRestApiClient(createDmmf([model]))

    expect(result).toContain('export interface UserCreateInput {')
    expect(result).toContain('  email: string')
    expect(result).toContain('  name?: string')
    // id has a default so it should be optional in create
    expect(result).toMatch(/export interface UserCreateInput \{[^}]*id\?: number/)
  })

  test('generates UpdateInput with all fields optional', () => {
    const model = createModel('User', [
      createField({ name: 'id', type: 'Int', isId: true }),
      createField({ name: 'email', type: 'String' }),
    ])

    const result = generateRestApiClient(createDmmf([model]))

    expect(result).toContain('export interface UserUpdateInput {')
    expect(result).toMatch(/export interface UserUpdateInput \{[^}]*id\?: number/)
    expect(result).toMatch(/export interface UserUpdateInput \{[^}]*email\?: string/)
  })

  test('generates WhereUniqueInput from unique/id fields', () => {
    const model = createModel('User', [
      createField({ name: 'id', type: 'Int', isId: true }),
      createField({ name: 'email', type: 'String', isUnique: true }),
      createField({ name: 'name', type: 'String' }),
    ])

    const result = generateRestApiClient(createDmmf([model]))

    expect(result).toContain('export interface UserWhereUniqueInput {')
    expect(result).toMatch(/export interface UserWhereUniqueInput \{[^}]*id\?: number/)
    expect(result).toMatch(/export interface UserWhereUniqueInput \{[^}]*email\?: string/)
    // name is not unique so it should not be in WhereUniqueInput
    expect(result).not.toMatch(/export interface UserWhereUniqueInput \{[^}]*name/)
  })

  test('generates WhereInput from scalar fields', () => {
    const model = createModel('User', [
      createField({ name: 'id', type: 'Int', isId: true }),
      createField({ name: 'email', type: 'String' }),
      createField({
        name: 'posts',
        type: 'Post',
        kind: 'object',
        isList: true,
      }),
    ])

    const result = generateRestApiClient(createDmmf([model]))

    expect(result).toContain('export interface UserWhereInput {')
    expect(result).toMatch(/export interface UserWhereInput \{[^}]*id\?: number/)
    expect(result).toMatch(/export interface UserWhereInput \{[^}]*email\?: string/)
    // relation field not in WhereInput
    expect(result).not.toMatch(/export interface UserWhereInput \{[^}]*posts/)
  })

  test('generates CRUD methods for each model', () => {
    const model = createModel('User', [
      createField({ name: 'id', type: 'Int', isId: true }),
      createField({ name: 'email', type: 'String' }),
    ])

    const result = generateRestApiClient(createDmmf([model]))

    expect(result).toContain('async userFindMany(where?: UserWhereInput): Promise<User[]>')
    expect(result).toContain(
      'async userFindUnique(where: UserWhereUniqueInput): Promise<User | null>',
    )
    expect(result).toContain('async userCreate(data: UserCreateInput): Promise<User>')
    expect(result).toContain(
      'async userUpdate(where: UserWhereUniqueInput, data: UserUpdateInput): Promise<User>',
    )
    expect(result).toContain('async userDelete(where: UserWhereUniqueInput): Promise<User>')
  })

  test('generates REST resource paths in kebab-case', () => {
    const model = createModel('BlogPost', [
      createField({ name: 'id', type: 'Int', isId: true }),
    ])

    const result = generateRestApiClient(createDmmf([model]))

    expect(result).toContain("path: '/blog-post'")
  })

  test('generates enum types', () => {
    const enumDef: DMMF.DatamodelEnum = {
      name: 'Role',
      values: [
        { name: 'ADMIN', dbName: null },
        { name: 'USER', dbName: null },
      ],
    }

    const model = createModel('User', [
      createField({ name: 'id', type: 'Int', isId: true }),
      createField({ name: 'role', type: 'Role', kind: 'enum' }),
    ])

    const result = generateRestApiClient(createDmmf([model], [enumDef]))

    expect(result).toContain('export enum Role {')
    expect(result).toContain("  ADMIN = 'ADMIN',")
    expect(result).toContain("  USER = 'USER',")
  })

  test('handles list fields', () => {
    const model = createModel('User', [
      createField({ name: 'id', type: 'Int', isId: true }),
      createField({ name: 'tags', type: 'String', isList: true }),
    ])

    const result = generateRestApiClient(createDmmf([model]))

    expect(result).toContain('  tags: string[]')
  })

  test('handles relation fields as optional in model interface', () => {
    const userModel = createModel('User', [
      createField({ name: 'id', type: 'Int', isId: true }),
      createField({
        name: 'posts',
        type: 'Post',
        kind: 'object',
        isList: true,
        isRequired: true,
      }),
    ])

    const postModel = createModel('Post', [
      createField({ name: 'id', type: 'Int', isId: true }),
      createField({
        name: 'author',
        type: 'User',
        kind: 'object',
        isRequired: true,
      }),
    ])

    const result = generateRestApiClient(createDmmf([userModel, postModel]))

    // Relations should be optional (might not be included in response)
    expect(result).toContain('  posts?: Post[]')
    expect(result).toContain('  author?: User')
  })

  test('excludes relation fields from CreateInput', () => {
    const model = createModel('Post', [
      createField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
      createField({ name: 'title', type: 'String' }),
      createField({
        name: 'author',
        type: 'User',
        kind: 'object',
        isRequired: true,
      }),
      createField({ name: 'authorId', type: 'Int', isReadOnly: true }),
    ])

    const result = generateRestApiClient(createDmmf([model]))

    // CreateInput should have title, but not author (relation) or authorId (readOnly)
    expect(result).toMatch(/export interface PostCreateInput \{[^}]*title: string/)
    expect(result).not.toMatch(/export interface PostCreateInput \{[^}]*author/)
    expect(result).not.toMatch(/export interface PostCreateInput \{[^}]*authorId/)
  })

  test('generates multiple models with their own CRUD methods', () => {
    const userModel = createModel('User', [
      createField({ name: 'id', type: 'Int', isId: true }),
    ])
    const postModel = createModel('Post', [
      createField({ name: 'id', type: 'Int', isId: true }),
    ])

    const result = generateRestApiClient(createDmmf([userModel, postModel]))

    expect(result).toContain('export interface User {')
    expect(result).toContain('export interface Post {')
    expect(result).toContain('async userFindMany')
    expect(result).toContain('async postFindMany')
    expect(result).toContain('async userCreate')
    expect(result).toContain('async postCreate')
  })

  test('generates RestApiClient class', () => {
    const result = generateRestApiClient(createDmmf([]))

    expect(result).toContain('export class RestApiClient {')
    expect(result).toContain('constructor(config: RestApiClientConfig)')
    expect(result).toContain('#request')
  })

  test('model with documentation includes JSDoc', () => {
    const model: DMMF.Model = {
      ...createModel('User', [createField({ name: 'id', type: 'Int', isId: true })]),
      documentation: 'A user in the system',
    }

    const result = generateRestApiClient(createDmmf([model]))

    expect(result).toContain('/** A user in the system */')
  })
})

