      enumTypes: { prisma: [] },
      fieldRefTypes: {},
    },
    mappings: {
      modelOperations: [],
      otherOperations: { read: [], write: [] },
    },
  }

  const generatorConfig: GeneratorConfig = {
    name: 'rest-api',
    output: { fromEnvVar: null, value: outputDir },
    provider: { fromEnvVar: null, value: 'prisma-rest-api-generator' },
    config: {},
    binaryTargets: [],
    previewFeatures: [],
    sourceFilePath: '/tmp/schema.prisma',
  }

  return {
    generator: generatorConfig,
    otherGenerators: [],
    schemaPath: '/tmp/schema.prisma',
    dmmf,
    datasources: [],
    datamodel: '',
    version: '0.0.0',
  }
}

describe('RestApiGenerator', () => {
  let tmpDir: string
  const generator = new RestApiGenerator()

  beforeEach(() => {
    tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'prisma-rest-api-gen-'))
  })

  afterEach(() => {
    fs.rmSync(tmpDir, { recursive: true, force: true })
  })

  test('getManifest returns correct metadata', async () => {
    const config: GeneratorConfig = {
      name: 'rest-api',
      output: null,
      provider: { fromEnvVar: null, value: 'prisma-rest-api-generator' },
      config: {},
      binaryTargets: [],
      previewFeatures: [],
      sourceFilePath: '/tmp/schema.prisma',
    }

    const manifest = await generator.getManifest(config)

    expect(manifest.prettyName).toBe('Prisma REST API Client')
    expect(manifest.defaultOutput).toBe('./generated/rest-api-client')
  })

  test('generate creates output directory and index.ts', async () => {
    const outputDir = path.join(tmpDir, 'output')
    const options = createMinimalOptions(outputDir)

    await generator.generate(options)

    const outputFile = path.join(outputDir, 'index.ts')
    expect(fs.existsSync(outputFile)).toBe(true)

