    expect(content).toContain('export interface User {')
    expect(content).toContain('export interface UserCreateInput {')
    expect(content).toContain('export interface UserUpdateInput {')
    expect(content).toContain('export interface UserWhereUniqueInput {')
    expect(content).toContain('export interface UserWhereInput {')
    expect(content).toContain('export class RestApiClient {')
    expect(content).toContain('async userFindMany')
    expect(content).toContain('async userFindUnique')
    expect(content).toContain('async userCreate')
    expect(content).toContain('async userUpdate')
    expect(content).toContain('async userDelete')
  })

  test('generate throws if no output specified', async () => {
    const options = createMinimalOptions(tmpDir)
    options.generator.output = null

    await expect(generator.generate(options)).rejects.toThrow(
      'No output directory specified for prisma-rest-api-generator',
    )
  })

  test('generate creates nested output directories', async () => {
    const outputDir = path.join(tmpDir, 'deeply', 'nested', 'output')
    const options = createMinimalOptions(outputDir)

    await generator.generate(options)

    expect(fs.existsSync(path.join(outputDir, 'index.ts'))).toBe(true)
  })
})

